import { useState, useEffect } from 'react';
import { auth, db } from '../firebase/config'; // Importez l'instance déjà configurée
import { 
  onAuthStateChanged, 
  signInAnonymously, 
  signInWithEmailAndPassword, 
  signOut,
  createUserWithEmailAndPassword
} from 'firebase/auth';
import { doc, getDoc, setDoc, updateDoc, query, where, collection, getDocs } from 'firebase/firestore';

export function useAuth() {
  const [user, setUser] = useState(null);
  const [userData, setUserData] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Écouteur de session
    const unsubscribe = onAuthStateChanged(auth, async (currentUser) => {
      console.log("🔥 État Auth changé :", currentUser ? "Connecté " + currentUser.uid : "Déconnecté");
      setUser(currentUser);
      if (currentUser) {
        const userDocRef = doc(db, 'users', currentUser.uid);
        const userDoc = await getDoc(userDocRef);
        if (userDoc.exists()) {
          setUserData(userDoc.data());
        } else {
          const defaultData = { role: 'regular', email: currentUser.email };
          await setDoc(userDocRef, defaultData);
          setUserData(defaultData);
        }
      } else {
        setUserData(null);
      }
      setLoading(false);
    });
    return () => unsubscribe();
  }, []);

  useEffect(() => {
    const initializeAdmin = async () => {
      // Only attempt to initialize if we haven't checked/initialized in this session
      // to avoid constant console noise and Firebase Auth requests.
      if (window._adminInitialized) return;
      window._adminInitialized = true;

      try {
        const adminEmail = 'admin@example.com';
        const userCredential = await createUserWithEmailAndPassword(auth, adminEmail, '123456');
        const userDoc = doc(db, 'users', userCredential.user.uid);
        await setDoc(userDoc, { role: 'admin', email: adminEmail });
        await signOut(auth);
      } catch (error) {
        // 'auth/email-already-in-use' is the standard SDK error code
        if (error.code === 'auth/email-already-in-use' || error.message?.includes('EMAIL_EXISTS')) {
          // User exists, ensure their role is admin in Firestore
          try {
            const q = query(collection(db, 'users'), where('email', '==', 'admin@example.com'));
            const querySnapshot = await getDocs(q);
            if (!querySnapshot.empty) {
              const userDoc = querySnapshot.docs[0];
              const data = userDoc.data();
              if (data.role !== 'admin') {
                await updateDoc(userDoc.ref, { role: 'admin' });
              }
            }
          } catch (fsError) {
            console.warn('Admin Firestore check failed (likely permissions):', fsError.message);
          }
        } else {
          // Ignore other errors during auto-init to keep console clean, 
          // or log them as warnings if they aren't critical.
          console.debug('Admin auto-init skipped or failed:', error.code);
        }
      }
    };
    initializeAdmin();
  }, []);

  const loginAnonymously = async () => {
    try {
      setLoading(true);
      await signInAnonymously(auth);
    } catch (err) {
      console.error("❌ Échec Anonyme :", err.code, err.message);
    } finally {
      setLoading(false);
    }
  };

  const loginEmail = async (email, password) => {
    try {
      setLoading(true);
      await signInWithEmailAndPassword(auth, email, password);
    } catch (err) {
      console.error("❌ Échec Email :", err.code, err.message);
      throw err;
    } finally {
      setLoading(false);
    }
  };

  const logout = () => signOut(auth);

  return { user, userData, loading, loginAnonymously, loginEmail, logout };
}

import { useState, useEffect } from 'react';
import { Routes, Route, useLocation } from 'react-router-dom';
import { useAuth } from './hooks/useAuth';
import { useAudio } from './hooks/useAudio';
import { useTables } from './hooks/useTables';
import { useInventory } from './hooks/useInventory';
import { CardProvider } from './contexts/CardContext';
import Login from './components/Login';
import Header from './components/Header';
import TableGrid from './components/TableGrid';
import StatusDashboard from './components/StatusDashboard';
import ShoppingList from './components/ShoppingList';
import ActivityLog from './components/ActivityLog';
import RequirementsCard from './components/RequirementsCard';
import FeaturesCard from './components/FeaturesCard';
import FooterLinks from './components/FooterLinks';
import AdminPanel from './components/AdminPanel';
import Manual from './components/Manual';
import Inventory from './components/Inventory';
import MultiPage1 from './components/MultiPage1';
import CleaningChecklist from './components/CleaningChecklist';
import CleaningCard from './components/CleaningCard';
import ProductForm from './components/ProductForm'; // <-- Existing import
import ProductList from './components/ProductList'; // <-- New import
import ClientSuggestions from './components/ClientSuggestions'; // <-- Existing import
import ProductDecisions from './components/ProductDecisions'; // <-- New import
import ProductReporting from './components/ProductReporting'; // <-- New import
import getAppVersionInfo from './versionInfo'; // Import the version info module

import { useSettings } from './hooks/useSettings';

function App() {
  const { user, userData, loading, loginEmail, loginAnonymously, logout } = useAuth();
  const { tables } = useTables();
  const { inventory } = useInventory();
  const { settings } = useSettings();
  const { isAudioEnabled, initAudio, playNotificationSound } = useAudio(tables, inventory, settings);

  const [titleSuffix, setTitleSuffix] = useState('');
  const appVersionInfo = getAppVersionInfo(); // Get the app version information
  const location = useLocation(); // Get current location

  // Determine currentPage based on pathname
  let currentPage = '';
  if (location.pathname === '/') {
    currentPage = 'dashboard';
  } else if (location.pathname === '/cleaning') {
    currentPage = 'cleaning';
  }
  // Add more conditions for other pages as needed

  useEffect(() => {
    const env = import.meta.env.MODE;
    let suffix = '';
    if (env === 'development') {
      suffix = ' [DEV]';
    } else if (env === 'staging') {
      suffix = ' [STAGING]';
    }
    document.title += suffix;
    setTitleSuffix(suffix);
  }, []);

  // ÉTAPE 1 : Attendre que Firebase réponde
  if (loading) {
    return (
      <div className="min-h-screen bg-[#0a0a0a] flex items-center justify-center">
        <div className="text-[#d4af37] animate-pulse font-bold uppercase tracking-[0.3em]">
          Mictlán...
        </div>
      </div>
    );
  }

  // ÉTAPE 2 : Si pas d'utilisateur, on force l'affichage du Login uniquement
  if (!user) {
    return <Login onLogin={loginEmail} onAnonymousLogin={loginAnonymously} />;
  }

  // ÉTAPE 3 : Si connecté, on affiche le Dashboard
  return (
    <div className="min-h-screen bg-[#0a0a0a] text-gray-200">
      <Header user={user} onLogout={logout} isAudioEnabled={isAudioEnabled} onEnableAudio={initAudio} titleSuffix={titleSuffix} />
      <Manual userData={userData} currentPage={currentPage} />
      <CardProvider>
        <Routes>
          <Route path="/" element={
            <main className="container mx-auto py-8 flex flex-col gap-12 px-4">
              <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                <TableGrid playNotificationSound={playNotificationSound} />
                <StatusDashboard />
                <Inventory user={user} />
                <ShoppingList />
                <ActivityLog />
                <CleaningCard />
                <ClientSuggestions />
                <ProductDecisions /> {/* <-- New component */} {/* <-- New component */}
              </div>
              <FooterLinks versionInfo={appVersionInfo.fullVersion} /> {/* Pass version info to FooterLinks */}
              <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                {userData?.role === 'admin' && <AdminPanel />}
                {userData?.role === 'admin' && <FeaturesCard />}
                {userData?.role === 'admin' && <RequirementsCard />}
                {userData?.role === 'admin' && <ProductForm />} {/* <-- New component */}
                {userData?.role === 'admin' && <ProductList />} {/* <-- New component */}
                {userData?.role === 'admin' && <ProductReporting />} {/* <-- New component */}
              </div>
            </main>
          } />
          <Route path="/multipage1" element={<MultiPage1 />} />
          <Route path="/cleaning" element={<CleaningChecklist />} />
        </Routes>
      </CardProvider>
    </div>
  );
}

export default App;

import { useState, useEffect } from 'react';
import { Volume2, VolumeX } from 'lucide-react';

// Fonction pour capitaliser la première lettre
const capitalize = (s) => s.charAt(0).toUpperCase() + s.slice(1);

export default function Header({ user, onLogout, isAudioEnabled, onEnableAudio, titleSuffix }) {
  const prNumber = import.meta.env.VITE_GITHUB_PR_NUMBER;
  const currentMode = import.meta.env.MODE;

  const [dateTimeString, setDateTimeString] = useState('');
  const [weatherData, setWeatherData] = useState(null);

  // Effet pour récupérer les données météo
  useEffect(() => {
    const fetchWeather = async () => {
      const apiKey = import.meta.env.VITE_OPENWEATHER_API_KEY;
      const city = 'Paris,FR';

      if (!apiKey) {
        console.error("Clé API OpenWeatherMap non trouvée. Assurez-vous d'avoir un fichier .env.local avec VITE_OPENWEATHER_API_KEY.");
        setWeatherData({ description: 'Erreur config', temperature: 'N/A' });
        return;
      }

      try {
        const response = await fetch(`https://api.openweathermap.org/data/2.5/weather?q=${city}&appid=${apiKey}&units=metric&lang=fr`);
        if (!response.ok) {
          throw new Error('Réponse réseau non OK');
        }
        const data = await response.json();
        setWeatherData({
          description: data.weather[0].description,
          temperature: Math.round(data.main.temp),
        });
      } catch (error) {
        console.error("Erreur de récupération météo:", error);
        setWeatherData({ description: 'Erreur API', temperature: 'N/A' });
      }
    };

    fetchWeather(); // Appel initial
    const interval = setInterval(fetchWeather, 600000); // Rafraîchir toutes les 10 minutes

    return () => clearInterval(interval); // Nettoyage
  }, []);

  // Effet pour mettre à jour l'affichage de l'heure et de la météo
  useEffect(() => {
    const formatDateTime = () => {
      const now = new Date();
      const datePart = new Intl.DateTimeFormat('fr-FR', {
        weekday: 'long', day: 'numeric', month: 'long', year: 'numeric',
      }).format(now);
      const timePart = new Intl.DateTimeFormat('fr-FR', {
        hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: false,
      }).format(now).replace(/:/g, 'h');

      let weatherString = 'Chargement de la météo...';
      if (weatherData) {
        weatherString = `${capitalize(weatherData.description)} - ${weatherData.temperature}°C`;
      }
      
      return `${capitalize(datePart)} - ${timePart} - ${weatherString}`;
    };

    const intervalId = setInterval(() => {
      setDateTimeString(formatDateTime());
    }, 1000);

    return () => clearInterval(intervalId);
  }, [weatherData]);

  let prDisplay = null;

  if (prNumber) { // If PR number is available (e.g. CI deployment)
    prDisplay = (
      <div className="text-gray-500 text-sm mb-1">
        [PR #{prNumber}]
      </div>
    );
  } else if (currentMode === 'development') {
    prDisplay = (
      <div className="text-gray-500 text-sm mb-1">
        PR not available (dev mode)
      </div>
    );
  } else if (currentMode === 'staging') { // Explicitly check for staging mode
      prDisplay = (
        <div className="text-gray-500 text-sm mb-1">
          Staging Mode: PR not available locally
        </div>
      );
  }

  return (
    <header className="text-center mb-4 sm:mb-8 relative flex flex-col items-center">
      {prDisplay}
      <img src="/mictlan-logo.png" alt="Mictlan Logo" className="w-24 h-auto" style={{ height: '80px', width: 'auto' }} />
      <div className="absolute top-0 right-0 p-2">
        <button onClick={onEnableAudio} className="p-2 text-white">
          {isAudioEnabled ? <Volume2 /> : <VolumeX className="text-red-500" />}
        </button>
      </div>

      <h1 className="text-3xl font-bold text-yellow-500 mb-2">
        Dashboard Le Mictlan{titleSuffix}
      </h1>
      <p className="text-gray-400 text-sm font-mono mt-2">{dateTimeString}</p> {/* Ajout de la date/heure/météo */}

      <div className="text-white">
        {user ? (
          <div className="flex flex-col items-center gap-2">
            <span className="text-green-400 text-sm">Connecté: {user.isAnonymous ? 'Anonyme' : user.email}</span>
            <button onClick={onLogout} className="text-xs text-gray-400 underline">Déconnexion</button>
          </div>
        ) : (
          <span className="text-red-400 text-sm">Déconnecté</span>
        )}
      </div>
    </header>
  );
}

import { useState } from 'react';
import { Settings, RefreshCw, Trash2, PackagePlus } from 'lucide-react';
import { resetDatabase, emptyDatabase } from '../firebase/dbActions';
import Card from './Card';

export default function AdminPanel() {
  const [tableCount, setTableCount] = useState(4);
  const [isUpdating, setIsUpdating] = useState(false);
  const [isEmptying, setIsEmptying] = useState(false);
  const [isPopulatingProducts, setIsPopulatingProducts] = useState(false);
  const [isClearingProducts, setIsClearingProducts] = useState(false);
  const [productFeedback, setProductFeedback] = useState('');
  const [isPopulatingDishes, setIsPopulatingDishes] = useState(false);
  const [dishesFeedback, setDishesFeedback] = useState('');

  const cloudFunctionsBaseUrl = `https://us-central1-${import.meta.env.VITE_FIREBASE_PROJECT_ID}.cloudfunctions.net`;

  const handleReset = async () => {
    setIsUpdating(true);
    try {
      await resetDatabase(tableCount);
    } catch {
      alert("Erreur lors de la mise à jour");
    } finally {
      setIsUpdating(false);
    }
  };

  const handleEmpty = async () => {
    if (!confirm("Êtes-vous sûr de vouloir vider complètement la base de données ? Cette action est irréversible.")) {
      return;
    }
    setIsEmptying(true);
    try {
      await emptyDatabase();
      alert("Base de données vidée avec succès.");
    } catch {
      alert("Erreur lors du vidage de la base de données");
    }
    finally {
      setIsEmptying(false);
    }
  };

  const handlePopulateProducts = async () => {
      setIsPopulatingProducts(true);
      setProductFeedback('Remplissage des produits de test...');
      
      try {
        const response = await fetch(`${cloudFunctionsBaseUrl}/populateProducts`, { 
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({}) // Explicitly send an empty JSON body
        });
        if (!response.ok) {
          throw new Error(`HTTP error! status: ${response.status}`);
        }
        const result = await response.json();
        setProductFeedback(result.message || 'Produits de test ajoutés avec succès !');
      } catch (error) {
          console.error("Error populating products:", error);
          setProductFeedback(`Erreur lors du remplissage des produits: ${error.message}`);
      } finally {
          setIsPopulatingProducts(false);
          setTimeout(() => setProductFeedback(''), 3000);
      }
  };

  const handleClearProducts = async () => {
      if (!confirm("Êtes-vous sûr de vouloir vider la collection de produits ? Cette action est irréversible.")) {
          return;
      }
      setIsClearingProducts(true);
      setProductFeedback('Vidage de la collection de produits...');
      
      try {
        const response = await fetch(`${cloudFunctionsBaseUrl}/clearProducts`, { 
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({}) // Explicitly send an empty JSON body
        });
        if (!response.ok) {
          throw new Error(`HTTP error! status: ${response.status}`);
        }
        const result = await response.json();
        setProductFeedback(result.message || 'Collection de produits vidée avec succès.');
      } catch (error) {
          console.error("Error clearing products:", error);
          setProductFeedback(`Erreur lors du vidage des produits: ${error.message}`);
      } finally {
          setIsClearingProducts(false);
          setTimeout(() => setProductFeedback(''), 3000);
      }
  };

  const handlePopulateDishes = async () => {
      setIsPopulatingDishes(true);
      setDishesFeedback('Remplissage des plats de test...');
      
      try {
        const response = await fetch(`${cloudFunctionsBaseUrl}/populateDishes`, { 
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({}) // Explicitly send an empty JSON body
        });
        if (!response.ok) {
          throw new Error(`HTTP error! status: ${response.status}`);
        }
        const result = await response.json();
        setDishesFeedback(result.message || 'Plats de test ajoutés avec succès !');
      } catch (error) {
          console.error("Error populating dishes:", error);
          setDishesFeedback(`Erreur lors du remplissage des plats: ${error.message}`);
      } finally {
          setIsPopulatingDishes(false);
          setTimeout(() => setDishesFeedback(''), 3000);
      }
  };

  return (
    <Card title="Configuration Système" titleIcon={<Settings />}>
      <div className="flex items-end gap-4 mb-4">
        <div className="flex-1">
          <label className="block text-gray-500 text-[9px] uppercase mb-1">Nombre de tables en salle</label>
          <input 
            type="number" 
            value={tableCount}
            onChange={(e) => setTableCount(e.target.value)}
            className="w-full bg-black border border-gray-800 rounded p-2 text-white outline-none focus:border-mictlan-gold"
            min="1"
            max="50"
          />
        </div>
        
        <button 
          onClick={handleReset}
          disabled={isUpdating}
          className="bg-black/40 text-gray-500 rounded-lg border border-gray-800 hover:text-mictlan-gold transition-all px-4 py-2 font-bold text-[10px] uppercase flex items-center gap-2"
        >
          <RefreshCw className={`w-3 h-3 ${isUpdating ? 'animate-spin' : ''}`} />
          {isUpdating ? 'Mise à jour...' : 'Réinitialiser Salle'}
        </button>
        <button 
          onClick={handleEmpty}
          disabled={isEmptying}
          className="bg-black/40 text-gray-500 rounded-lg border border-gray-800 hover:text-mictlan-gold transition-all px-4 py-2 font-bold text-[10px] uppercase flex items-center gap-2"
        >
          <Trash2 className={`w-3 h-3 ${isEmptying ? 'animate-spin' : ''}`} />
          {isEmptying ? 'Vidage...' : 'Vider DB'}
        </button>
      </div>
      <p className="text-[8px] text-gray-600 mt-2 italic font-mono uppercase">
        * Réinitialiser Salle : Efface toutes les données actuelles pour générer {tableCount} tables. Vider DB : Supprime toutes les données des collections connues (tables, inventory, logs, users). Pour vider toutes les collections inconnues, exécutez `npm run empty-db` or `node empty-db.cjs` dans un terminal.
      </p>

      <div className="flex flex-col gap-4 mb-4 mt-4 border-t border-gray-700 pt-4">
        <label className="block text-sm font-black text-mictlan-gold uppercase tracking-[0.2em] mb-2">
          Gestion des Produits de Test
        </label>
        <div className="flex gap-4">
          <button 
            onClick={handlePopulateProducts}
            disabled={isPopulatingProducts}
            className="flex-1 bg-black/40 text-gray-500 rounded-lg border border-gray-800 hover:text-mictlan-gold transition-all px-4 py-2 font-bold text-[10px] uppercase flex items-center justify-center gap-2"
          >
            <PackagePlus className={`w-3 h-3 ${isPopulatingProducts ? 'animate-spin' : ''}`} />
            {isPopulatingProducts ? 'Remplissage...' : 'Remplir Produits'}
          </button>
          <button 
            onClick={handleClearProducts}
            disabled={isClearingProducts}
            className="flex-1 bg-black/40 text-gray-500 rounded-lg border border-gray-800 hover:text-mictlan-red transition-all px-4 py-2 font-bold text-[10px] uppercase flex items-center justify-center gap-2"
          >
            <Trash2 className={`w-3 h-3 ${isClearingProducts ? 'animate-spin' : ''}`} />
            {isClearingProducts ? 'Vidage...' : 'Vider Produits'}
          </button>
        </div>
        {productFeedback && <p className="text-[10px] text-center text-mictlan-gold mt-2">{productFeedback}</p>}
      </div>

      <div className="flex flex-col gap-4 mb-4 mt-4 border-t border-gray-700 pt-4">
        <label className="block text-sm font-black text-mictlan-gold uppercase tracking-[0.2em] mb-2">
          Gestion des Plats de Test
        </label>
        <div className="flex gap-4">
          <button 
            onClick={handlePopulateDishes}
            disabled={isPopulatingDishes}
            className="flex-1 bg-black/40 text-gray-500 rounded-lg border border-gray-800 hover:text-mictlan-gold transition-all px-4 py-2 font-bold text-[10px] uppercase flex items-center justify-center gap-2"
          >
            <PackagePlus className={`w-3 h-3 ${isPopulatingDishes ? 'animate-spin' : ''}`} />
            {isPopulatingDishes ? 'Remplissage...' : 'Remplir Plats'}
          </button>
        </div>
        {dishesFeedback && <p className="text-[10px] text-center text-mictlan-gold mt-2">{dishesFeedback}</p>}
      </div>
    </Card>
  );
}

