import { Package, AlertTriangle, CheckCircle, XCircle, PlusCircle, Trash2 } from 'lucide-react'; // Import PlusCircle and Trash2
import { useInventory } from '../hooks/useInventory';
import { useLogs } from '../hooks/useLogs';
import { useAuth } from '../hooks/useAuth'; // Import useAuth
import Card from './Card';

export default function Inventory({ user }) {
  const { inventory, updateStatus, addInventoryItem, removeInventoryItem } = useInventory(); // Destructure addInventoryItem and removeInventoryItem
  const { addLog } = useLogs();
  const { userData } = useAuth(); // Get user data
  const isAdmin = userData?.role === 'admin'; // Check for admin role

  const [newItemName, setNewItemName] = useState('');
  const [newItemCategory, setNewItemCategory] = useState('');

  const getStatusColor = (status) => {
    switch (status) {
      case 'ok': return 'text-green-500';
      case 'low': return 'text-orange-500';
      case 'out': return 'text-red-600 animate-pulse';
      default: return 'text-gray-500';
    }
  };

  const getStatusIcon = (status) => {
    switch (status) {
      case 'ok': return <CheckCircle size={16} className="text-green-500" />;
      case 'low': return <AlertTriangle size={16} className="text-orange-500" />;
      case 'out': return <XCircle size={16} className="text-red-600" />;
      default: return <Package size={16} className="text-gray-500" />;
    }
  };

  const handleStatusClick = async (item) => {
    const statusCycle = { ok: 'low', low: 'out', out: 'ok' };
    const nextStatus = statusCycle[item.status] || 'ok';
    await updateStatus(item.id, nextStatus, item.name, addLog, user);
  };

  const handleAddInventoryItem = async (e) => {
    e.preventDefault();
    if (!newItemName.trim()) {
      alert("Le nom de l&#39;article ne peut pas être vide.");
      return;
    }
    try {
      await addInventoryItem(newItemName.trim(), newItemCategory.trim(), addLog, user);
      setNewItemName('');
      setNewItemCategory('');
    } catch (error) {
      alert("Erreur lors de l'ajout de l'article: " + error.message);
    }
  };

  const handleRemoveInventoryItem = async (itemId, itemName) => {
    if (window.confirm(`Êtes-vous sûr de vouloir supprimer "${itemName}" de l'inventaire ?`)) {
      try {
        await removeInventoryItem(itemId, itemName, addLog, user);
      } catch (error) {
        alert("Erreur lors de la suppression de l'article: " + error.message);
      }
    }
  };

  return (
    <Card title="Inventaire" titleIcon={<Package />}>
      <>
        {isAdmin && (
          <div className="mb-6 p-4 bg-black/30 rounded-lg border border-gray-700">
            <h3 className="text-mictlan-gold font-bold uppercase text-xs mb-3 flex items-center gap-2">
              <PlusCircle size={14} /> Ajouter un article
            </h3>
            <form onSubmit={handleAddInventoryItem} className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div>
                <label htmlFor="itemName" className="block text-gray-400 text-xs font-bold mb-1">Nom de l&apos;article</label>
                <input
                  type="text"
                  id="itemName"
                  value={newItemName}
                  onChange={(e) => setNewItemName(e.target.value)}
                  className="w-full p-2 bg-black/40 text-white border border-gray-600 rounded-md focus:outline-none focus:ring-1 focus:ring-mictlan-gold"
                  placeholder="Ex: Serviettes, Verres..."
                />
              </div>
              <div>
                <label htmlFor="itemCategory" className="block text-gray-400 text-xs font-bold mb-1">Catégorie (optionnel)</label>
                <input
                  type="text"
                  id="itemCategory"
                  value={newItemCategory}
                  onChange={(e) => setNewItemCategory(e.target.value)}
                  className="w-full p-2 bg-black/40 text-white border border-gray-600 rounded-md focus:outline-none focus:ring-1 focus:ring-mictlan-gold"
                  placeholder="Ex: Consommable, Vaisselle..."
                />
              </div>
              <div className="md:col-span-2 flex justify-end gap-2">
                <button
                  type="button"
                  onClick={() => { setNewItemName(''); setNewItemCategory(''); }}
                  className="px-4 py-2 bg-gray-700 text-white rounded-md hover:bg-gray-600 transition-colors text-sm"
                >
                  Annuler
                </button>
                <button
                  type="submit"
                  className="px-4 py-2 bg-mictlan-gold text-black rounded-md hover:bg-[#b8942a] transition-colors text-sm font-bold"
                >
                  Ajouter
                </button>
              </div>
            </form>
          </div>
        )}

        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-3">
          {inventory.map((item) => (
            <div
              key={item.id}
              onClick={() => handleStatusClick(item)}
              className="bg-black/30 p-3 rounded-lg border border-gray-800 hover:border-mictlan-gold/50 cursor-pointer transition-all group relative" // Added relative for absolute positioning of delete button
            >
              {isAdmin && ( // Admin only delete button
                <button
                  onClick={(e) => {
                    e.stopPropagation(); // Prevent status click when delete button is clicked
                    handleRemoveInventoryItem(item.id, item.name);
                  }}
                  className="absolute top-2 right-2 p-1.5 bg-black/50 text-gray-400 rounded-full hover:text-mictlan-red hover:bg-black/80 transition-all"
                  aria-label={`Supprimer ${item.name}`}
                >
                  <Trash2 size={14} />
                </button>
              )}
              <div className="flex items-center justify-between mb-2">
                <span className="text-xs font-medium text-gray-300 uppercase tracking-wide">
                  {item.name}
                </span>
                {getStatusIcon(item.status)}
              </div>
              <div className={`text-xs font-bold ${getStatusColor(item.status)}`}>
                {item.status === 'ok' ? 'EN STOCK' :
                 item.status === 'low' ? 'STOCK FAIBLE' :
                 item.status === 'out' ? 'ÉPUISÉ' : 'INCONNU'}
              </div>
              {item.quantity && (
                <div className="text-[10px] text-gray-500 mt-1">
                  Qté: {item.quantity}
                </div>
              )}
            </div>
          ))}
        </div>

        {inventory.length === 0 && (
          <div className="text-center py-8 text-gray-500">
            <Package size={48} className="mx-auto mb-4 opacity-50" />
            <p className="text-sm">Aucun article en inventaire</p>
          </div>
        )}
      </>
    </Card>
  );
}

import { useState, useEffect } from 'react';
import { Routes, Route, useLocation } from 'react-router-dom';
import { useAuth } from './hooks/useAuth';
import { useAudio } from './hooks/useAudio';
import { useTables } from './hooks/useTables';
import { useInventory } from './hooks/useInventory';
import { CardProvider } from './contexts/CardContext';
import Login from './components/Login';
import Header from './components/Header';
import TableGrid from './components/TableGrid';
import StatusDashboard from './components/StatusDashboard';
import ShoppingList from './components/ShoppingList';
import ActivityLog from './components/ActivityLog';
import RequirementsCard from './components/RequirementsCard';
import FeaturesCard from './components/FeaturesCard';
import FooterLinks from './components/FooterLinks';
import AdminPanel from './components/AdminPanel';
import Manual from './components/Manual';
import Inventory from './components/Inventory';
import MultiPage1 from './components/MultiPage1';
import CleaningChecklist from './components/CleaningChecklist';
import CleaningCard from './components/CleaningCard';
import ProductForm from './components/ProductForm'; // <-- Existing import
import ProductList from './components/ProductList'; // <-- New import
import ClientSuggestions from './components/ClientSuggestions'; // <-- Existing import
import ProductDecisions from './components/ProductDecisions'; // <-- New import
import ProductReporting from './components/ProductReporting'; // <-- New import
import getAppVersionInfo from './versionInfo'; // Import the version info module

import { useSettings } from './hooks/useSettings';

function App() {
  const { user, userData, loading, loginEmail, loginAnonymously, logout } = useAuth();
  const { tables } = useTables();
  const { inventory } = useInventory();
  const { settings } = useSettings();
  const { isAudioEnabled, initAudio, playNotificationSound } = useAudio(tables, inventory, settings);

  const [showAdminView, setShowAdminView] = useState(false); // State for admin view
  const [titleSuffix, setTitleSuffix] = useState('');
  const appVersionInfo = getAppVersionInfo(); // Get the app version information
  const location = useLocation(); // Get current location

  // Determine currentPage based on pathname
  let currentPage = '';
  if (location.pathname === '/') {
    currentPage = 'dashboard';
  } else if (location.pathname === '/cleaning') {
    currentPage = 'cleaning';
  }
  // Add more conditions for other pages as needed

  useEffect(() => {
    const env = import.meta.env.MODE;
    let suffix = '';
    if (env === 'development') {
      suffix = ' [DEV]';
    } else if (env === 'staging') {
      suffix = ' [STAGING]';
    }
    document.title += suffix;
    setTitleSuffix(suffix);
  }, []);

  // ÉTAPE 1 : Attendre que Firebase réponde
  if (loading) {
    return (
      <div className="min-h-screen bg-[#0a0a0a] flex items-center justify-center">
        <div className="text-[#d4af37] animate-pulse font-bold uppercase tracking-[0.3em]">
          Mictlán...
        </div>
      </div>
    );
  }

  // ÉTAPE 2 : Si pas d'utilisateur, on force l'affichage du Login uniquement
  if (!user) {
    return <Login onLogin={loginEmail} onAnonymousLogin={loginAnonymously} />;
  }

  // ÉTAPE 3 : Si connecté, on affiche le Dashboard
  return (
    <div className="min-h-screen bg-[#0a0a0a] text-gray-200">
      <Header 
        user={user} 
        userData={userData}
        onLogout={logout} 
        isAudioEnabled={isAudioEnabled} 
        onEnableAudio={initAudio} 
        titleSuffix={titleSuffix}
        showAdminView={showAdminView}
        setShowAdminView={setShowAdminView}
      />
      <Manual userData={userData} currentPage={currentPage} showAdminView={showAdminView} />
      <CardProvider>
        <Routes>
          <Route path="/" element={
            <main className="container mx-auto py-8 flex flex-col gap-12 px-4">
              <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                <TableGrid 
                  playNotificationSound={playNotificationSound} 
                  showAdminView={showAdminView}
                  userData={userData}
                />
                <StatusDashboard />
                <Inventory user={user} />
                <ShoppingList />
                <ActivityLog />
                <CleaningCard />
                <ClientSuggestions />
                <ProductDecisions /> {/* <-- New component */} {/* <-- New component */}
              </div>
              <FooterLinks versionInfo={appVersionInfo.fullVersion} /> {/* Pass version info to FooterLinks */}
              <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                {userData?.role === 'admin' && showAdminView && <AdminPanel />}
                {userData?.role === 'admin' && showAdminView && <FeaturesCard />}
                {userData?.role === 'admin' && showAdminView && <RequirementsCard />}
                {userData?.role === 'admin' && showAdminView && <ProductForm />}
                {userData?.role === 'admin' && showAdminView && <ProductList />}
                {userData?.role === 'admin' && showAdminView && <ProductReporting />}
              </div>
            </main>
          } />
          <Route path="/multipage1" element={<MultiPage1 />} />
          <Route path="/cleaning" element={<CleaningChecklist />} />
        </Routes>
      </CardProvider>
    </div>
  );
}

export default App;

